import { useNavigate } from "react-router-dom";
import logo from "../assets/logo.png";

export default function Navbar() {
  const nav = useNavigate();

  return (
    <div style={{ background:"#eee", borderBottom:"1px solid #ccc" }}>

      <div style={{ display:"flex", justifyContent:"space-between", padding:"10px 30px" }}>

        <img src={logo} style={{ height:"100px" }} />

        <h1 style={{
          position:"absolute",
          left:"50%",
          transform:"translateX(-50%)"
        }}>
          AARV Train Booking System
        </h1>

        <div>
          <button onClick={()=>nav("/")}>Login</button>
          <button onClick={()=>nav("/signup")}>Signup</button>
        </div>
      </div>

      <div style={{ textAlign:"center", padding:"10px" }}>
        <button onClick={()=>nav("/home")}>Home</button>
        <button onClick={()=>nav("/my")}>Bookings</button>
        <button onClick={()=>nav("/account")}>Account</button>
      </div>

    </div>
  );
}
